function normalizeTitle(title: string): string {
  return title.toLowerCase().trim()
    .replace(/[^a-z0-9\s]/g, '')
    .replace(/\s+/g, ' ');
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);

    // Fetch ALL lessons with service role
    const acaLessons = await base44.asServiceRole.entities.Lesson.list();

    const results = {
      matched: 0,
      updated: 0,
      skipped_already_has_video: 0,
      no_match: [] as string[],
      errors: [] as { lesson: string; error: string }[],
      updates: [] as { lesson_id: string; title: string; video_url: string; duration_sec: number }[],
    };

    // Build normalized title lookup from WP data
    const wpMap = new Map<string, typeof WP_LESSONS[0]>();
    for (const wpLesson of WP_LESSONS) {
      const key = normalizeTitle(wpLesson.lesson_title);
      wpMap.set(key, wpLesson);
    }

    for (const acaLesson of acaLessons) {
      const key = normalizeTitle(acaLesson.title || '');
      const wpMatch = wpMap.get(key);

      if (!wpMatch) {
        results.no_match.push(acaLesson.title);
        continue;
      }

      results.matched++;

      // Skip if already has a video
      if (acaLesson.video_url && acaLesson.video_url.length > 5) {
        results.skipped_already_has_video++;
        continue;
      }

      try {
        await base44.asServiceRole.entities.Lesson.update(acaLesson.id, {
          video_url: wpMatch.video_url,
          video_provider: 'youtube',
          video_duration: Math.round(Number(wpMatch.duration_sec)),
        });
        results.updated++;
        results.updates.push({
          lesson_id: acaLesson.id,
          title: acaLesson.title,
          video_url: wpMatch.video_url,
          duration_sec: Math.round(Number(wpMatch.duration_sec)),
        });
      } catch (err: any) {
        results.errors.push({ lesson: acaLesson.title, error: err.message });
      }
    }

    return Response.json({
      success: true,
      summary: {
        total_aca_lessons: acaLessons.length,
        total_wp_youtube_lessons: WP_LESSONS.length,
        matched: results.matched,
        updated: results.updated,
        skipped_already_has_video: results.skipped_already_has_video,
        unmatched_count: results.no_match.length,
      },
      updates: results.updates,
      unmatched: results.no_match,
      errors: results.errors,
    });

  } catch (err: any) {
    return Response.json({ success: false, error: err.message }, { status: 500 });
  }
});
